import React, { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';
import { adminService } from '../../services/api';
import AdminRoundScheduling from './AdminRoundScheduling';

const styles = `
  @keyframes slideUp {
    from { opacity: 0; transform: translateY(20px); }
    to { opacity: 1; transform: translateY(0); }
  }
`;

const STATUS_CFG = {
  APPLIED:             { label: 'Applied',             cls: 'badge-applied' },
  APTITUDE_SCHEDULED:  { label: 'Aptitude Scheduled',  cls: 'badge-review' },
  APTITUDE_CLEARED:    { label: 'Aptitude Cleared',    cls: 'badge-approved' },
  APTITUDE_FAILED:     { label: 'Aptitude Failed',     cls: 'badge-rejected' },
  INTERVIEW_SCHEDULED: { label: 'Interview Scheduled', cls: 'badge-shortlisted' },
  SELECTED:            { label: '🎉 Selected',         cls: 'badge-selected' },
  REJECTED:            { label: 'Rejected',            cls: 'badge-rejected' },
};

const DEPT_ABBR = {
  'Computer Science & Engineering': 'CSE',
  'Electronics & Communication': 'ECE',
  'Mechanical Engineering': 'ME',
  'Civil Engineering': 'CE',
  'Electrical Engineering': 'EE',
  'Information Technology': 'IT',
  'Master of Computer Applications': 'MCA'
};

const getDeptFullName = (deptAbbr) => {
  if (!deptAbbr) return '—';
  const normalizedDept = deptAbbr.trim().toLowerCase();
  return Object.entries(DEPT_ABBR).find(([_, abbr]) => abbr.toLowerCase() === normalizedDept)?.[0] || deptAbbr;
};

export default function AdminJobApplicants() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [applicants, setApplicants] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selected, setSelected] = useState(null);
  const [showStudentModal, setShowStudentModal] = useState(false);
  const [showRoundScheduling, setShowRoundScheduling] = useState(false);
  const [showIntModal, setShowIntModal] = useState(false);
  const [showAptModal, setShowAptModal] = useState(false);
  const [showResultModal, setShowResultModal] = useState(false);
  const [actionApp, setActionApp] = useState(null);
  const [intForm, setIntForm] = useState({ interviewDate: '', interviewTime: '', interviewMode: 'Online' });
  const [aptForm, setAptForm] = useState({ cleared: true, score: '' });
  const [resultForm, setResultForm] = useState({ result: 'Pass', notes: '', finalSelected: true });
  const [saving, setSaving] = useState(false);

  const fetchData = () => {
  console.log("JOB ID:", id);   // 🔥 ADD THIS
  setLoading(true);

  adminService.getApplicants(id)
    .then(r => setApplicants(r.data))
    .catch(err => console.log(err))
    .finally(() => setLoading(false));
  };

  useEffect(() => {
    const styleSheet = document.createElement('style');
    styleSheet.textContent = styles;
    document.head.appendChild(styleSheet);
    return () => styleSheet.remove();
  }, []);

  useEffect(fetchData, [id]);

  const doScheduleAptitude = async appId => {
    try { await adminService.scheduleAptitude(appId); toast.success('Aptitude scheduled.'); fetchData(); }
    catch { toast.error('Failed.'); }
  };

  const doAptitudeResult = async e => {
    e.preventDefault(); setSaving(true);
    try {
      const clearedBool = aptForm.cleared === 'true' || aptForm.cleared === true;
      await adminService.aptitudeResult(actionApp.id, { cleared: clearedBool, score: aptForm.score ? parseInt(aptForm.score) : null });
      toast.success('Aptitude result recorded.'); setShowAptModal(false); fetchData();
    } catch (err) { 
      console.error('Aptitude error:', err.response?.data || err.message);
      toast.error(err.response?.data?.message || 'Failed.'); 
    }
    finally { setSaving(false); }
  };

  const doScheduleInterview = async e => {
    e.preventDefault(); setSaving(true);
    try {
      await adminService.scheduleInterview(actionApp.id, intForm);
      toast.success('Interview scheduled! Email sent.'); setShowIntModal(false); fetchData();
    } catch (err) { 
      console.error('Schedule interview error:', err.response?.data || err.message);
      toast.error(err.response?.data?.message || 'Failed.'); 
    }
    finally { setSaving(false); }
  };

  const doInterviewResult = async e => {
    e.preventDefault(); setSaving(true);
    try {
      const finalSelectedBool = resultForm.finalSelected === 'true' || resultForm.finalSelected === true;
      await adminService.interviewResult(actionApp.id, { 
        result: resultForm.result, 
        notes: resultForm.notes, 
        finalSelected: finalSelectedBool 
      });
      toast.success('Result recorded.'); setShowResultModal(false); fetchData();
    } catch (err) { 
      console.error('Error:', err);
      toast.error(err.response?.data?.message || 'Failed.'); 
    }
    finally { setSaving(false); }
  };

  const openModal = (app, type) => {
    setActionApp(app);
    if (type === 'aptitude') setShowAptModal(true);
    else if (type === 'interview') setShowIntModal(true);
    else setShowResultModal(true);
  };

  return (
    <>
      <div className="topbar">
        <div>
          <button onClick={() => navigate('/admin/jobs')} style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--gold)', fontSize: 13, marginBottom: 4 }}>← Back to Jobs</button>
          <div className="topbar-title">Job Applicants</div>
          <div className="topbar-sub">{applicants.length} applicant{applicants.length !== 1 ? 's' : ''} for this position</div>
        </div>
      </div>

      <div className="page-content">
        <div style={{ display: 'grid', gridTemplateColumns: selected ? '1fr 380px' : '1fr', gap: 20, alignItems: 'start' }}>
          <div className="card" style={{ padding: 0, overflow: 'hidden' }}>
            <div className="table-wrapper">
              <table>
                <thead><tr><th>Student</th><th>Dept</th><th>CGPA</th><th>Applied</th><th>Status</th><th>Actions</th></tr></thead>
                <tbody>
                  {loading && <tr><td colSpan={6} style={{ textAlign: 'center', padding: 32, color: 'var(--gray-400)' }}>Loading…</td></tr>}
                  {!loading && applicants.length === 0 && <tr><td colSpan={6} style={{ textAlign: 'center', padding: 32, color: 'var(--gray-400)' }}>No applicants yet.</td></tr>}
                  {applicants.map(a => {
                    const sc = STATUS_CFG[a.status] || { label: a.status, cls: 'badge-pending' };
                    return (
                      <tr key={a.id} style={{ cursor: 'pointer', background: selected?.id === a.id ? 'var(--off-white)' : '' }} onClick={() => setSelected(selected?.id === a.id ? null : a)}>
                        <td>
                          <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                            <div className="avatar avatar-sm">{a.studentName?.[0]}</div>
                            <div><div style={{ fontWeight: 500, fontSize: 13 }}>{a.studentName}</div><div style={{ fontSize: 11, color: 'var(--gray-400)' }}>{a.studentEmail}</div></div>
                          </div>
                        </td>
                        <td style={{ fontSize: 12 }}>{getDeptFullName(a.department)}</td>
                        <td style={{ fontWeight: 600 }}>{a.cgpa || '—'}</td>
                        <td style={{ fontSize: 12, color: 'var(--gray-400)' }}>{new Date(a.appliedAt).toLocaleDateString('en-IN', { day: 'numeric', month: 'short' })}</td>
                        <td><span className={`badge ${sc.cls}`}>{sc.label}</span></td>
                        <td onClick={e => e.stopPropagation()}>
                          <div style={{ display: 'flex', gap: 5, flexWrap: 'wrap' }}>
                            {a.status === 'APPLIED' && <button className="btn btn-sm btn-info" onClick={() => doScheduleAptitude(a.id)}>Schedule Aptitude</button>}
                            {a.status === 'APTITUDE_SCHEDULED' && <button className="btn btn-sm btn-outline" onClick={() => openModal(a, 'aptitude')}>Record Result</button>}
                            {a.status === 'APTITUDE_CLEARED' && <button className="btn btn-sm btn-primary" onClick={() => openModal(a, 'interview')}>Schedule Interview</button>}
                            {a.status === 'INTERVIEW_SCHEDULED' && <button className="btn btn-sm btn-gold" onClick={() => openModal(a, 'result')}>Record Result</button>}
                            {['SELECTED','REJECTED'].includes(a.status) && <span style={{ fontSize: 12, color: 'var(--gray-400)' }}>Completed</span>}
                          </div>
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          </div>

          {selected && (
            <div className="card" style={{ position: 'sticky', top: 80 }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 16 }}>
                <div style={{ fontWeight: 600, fontSize: 15, color: 'var(--navy)' }}>{selected.studentName}</div>
                <button onClick={() => setSelected(null)} style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--gray-400)', fontSize: 18 }}>✕</button>
              </div>
              <div style={{ display: 'flex', flexDirection: 'column', gap: 10, fontSize: 13 }}>
                {[
                  ['Email', selected.studentEmail],
                  ['Roll No.', selected.rollNumber],
                  ['Department', getDeptAbbr(selected.department)],
                  ['CGPA', selected.cgpa || '—'],
                  ['Status', <span className={`badge ${(STATUS_CFG[selected.status] || {}).cls}`}>{(STATUS_CFG[selected.status] || {}).label}</span>],
                  selected.aptitudeScore != null && ['Aptitude', `Score: ${selected.aptitudeScore} — ${selected.aptitudeCleared ? '✅ Cleared' : '❌ Failed'}`],
                  selected.interviewDate && ['Interview', `${selected.interviewDate} ${selected.interviewTime} (${selected.interviewMode})`],
                  selected.interviewResult && ['Int. Result', selected.interviewResult],
                  selected.interviewNotes && ['Notes', selected.interviewNotes],
                  selected.finalSelected != null && ['Final', selected.finalSelected ? '✅ Selected' : '❌ Not Selected'],
                ].filter(Boolean).map(([k, v]) => (
                  <div key={k} style={{ display: 'flex', gap: 8, borderBottom: '1px solid var(--gray-100)', paddingBottom: 8 }}>
                    <span style={{ color: 'var(--gray-400)', minWidth: 90, flexShrink: 0 }}>{k}</span>
                    <span style={{ fontWeight: 500 }}>{v}</span>
                  </div>
                ))}
              </div>

              <div style={{ display: 'flex', flexDirection: 'column', gap: 8, marginTop: 16 }}>
                {selected.status === 'APPLIED' && <button className="btn btn-info btn-full" onClick={() => doScheduleAptitude(selected.id)}>Schedule Aptitude Test</button>}
                {selected.status === 'APTITUDE_SCHEDULED' && <button className="btn btn-outline btn-full" onClick={() => openModal(selected, 'aptitude')}>Record Aptitude Result</button>}
                {selected.status === 'APTITUDE_CLEARED' && <button className="btn btn-primary btn-full" onClick={() => openModal(selected, 'interview')}>Schedule Interview</button>}
                {selected.status === 'INTERVIEW_SCHEDULED' && <button className="btn btn-gold btn-full" onClick={() => openModal(selected, 'result')}>Record Interview Result</button>}
                {['APTITUDE_CLEARED', 'INTERVIEW_SCHEDULED', 'SELECTED', 'REJECTED'].includes(selected.status) && <button className="btn btn-success btn-full" onClick={() => setShowRoundScheduling(true)}>Round Scheduling</button>}
                <button className="btn btn-outline btn-full" onClick={() => setShowStudentModal(true)}>View Full Profile</button>
              </div>
            </div>
          )}
        </div>
      </div>

      {/* Aptitude Result Modal */}
      {showAptModal && (
        <div className="modal-overlay" onClick={() => setShowAptModal(false)}>
          <div className="modal" onClick={e => e.stopPropagation()}>
            <h3 className="modal-title">Record Aptitude Result — {actionApp?.studentName}</h3>
            <form onSubmit={doAptitudeResult}>
              <div className="form-group"><label>Result</label>
                <select value={aptForm.cleared} onChange={e => setAptForm(p => ({ ...p, cleared: e.target.value }))}>
                  <option value="true">Cleared ✅</option><option value="false">Failed ❌</option>
                </select>
              </div>
              <div className="form-group"><label>Score (Optional)</label><input type="number" placeholder="e.g. 75" value={aptForm.score} onChange={e => setAptForm(p => ({ ...p, score: e.target.value }))} /></div>
              <div className="btn-row"><button type="button" className="btn btn-outline" onClick={() => setShowAptModal(false)}>Cancel</button><button type="submit" className="btn btn-primary" disabled={saving}>{saving ? 'Saving…' : 'Save Result'}</button></div>
            </form>
          </div>
        </div>
      )}

      {/* Schedule Interview Modal */}
      {showIntModal && (
        <div className="modal-overlay" onClick={() => setShowIntModal(false)}>
          <div className="modal" onClick={e => e.stopPropagation()}>
            <h3 className="modal-title">Schedule Interview — {actionApp?.studentName}</h3>
            <form onSubmit={doScheduleInterview}>
              <div className="form-row">
                <div className="form-group"><label>Date *</label><input type="date" required value={intForm.interviewDate} onChange={e => setIntForm(p => ({ ...p, interviewDate: e.target.value }))} /></div>
                <div className="form-group"><label>Time *</label><input type="time" required value={intForm.interviewTime} onChange={e => setIntForm(p => ({ ...p, interviewTime: e.target.value }))} /></div>
              </div>
              <div className="form-group"><label>Mode</label>
                <select value={intForm.interviewMode} onChange={e => setIntForm(p => ({ ...p, interviewMode: e.target.value }))}>
                  <option>Online</option><option>In-person</option><option>Phone</option>
                </select>
              </div>
              <div className="btn-row"><button type="button" className="btn btn-outline" onClick={() => setShowIntModal(false)}>Cancel</button><button type="submit" className="btn btn-primary" disabled={saving}>{saving ? 'Scheduling…' : 'Schedule & Notify'}</button></div>
            </form>
          </div>
        </div>
      )}

      {/* Interview Result Modal */}
      {showResultModal && (
        <div className="modal-overlay" onClick={() => setShowResultModal(false)}>
          <div className="modal" onClick={e => e.stopPropagation()}>
            <h3 className="modal-title">Interview Result — {actionApp?.studentName}</h3>
            <form onSubmit={doInterviewResult}>
              <div className="form-group"><label>Interview Result</label>
                <select value={resultForm.result} onChange={e => setResultForm(p => ({ ...p, result: e.target.value }))}>
                  <option>Pass</option><option>Fail</option><option>On Hold</option>
                </select>
              </div>
              <div className="form-group"><label>Final Selection Decision</label>
                <select value={resultForm.finalSelected} onChange={e => setResultForm(p => ({ ...p, finalSelected: e.target.value }))}>
                  <option value="true">Selected ✅</option><option value="false">Not Selected ❌</option>
                </select>
              </div>
              <div className="form-group"><label>Notes (Optional)</label><textarea rows={3} placeholder="Feedback or remarks…" value={resultForm.notes} onChange={e => setResultForm(p => ({ ...p, notes: e.target.value }))} /></div>
              <div className="btn-row"><button type="button" className="btn btn-outline" onClick={() => setShowResultModal(false)}>Cancel</button><button type="submit" className="btn btn-gold" disabled={saving}>{saving ? 'Saving…' : 'Save & Notify Student'}</button></div>
            </form>
          </div>
        </div>
      )}

      {/* Student Details Modal */}
      {showStudentModal && selected && (
        <div style={{
          position: 'fixed', top: 0, left: 0, right: 0, bottom: 0,
          background: 'rgba(0,0,0,0.5)', display: 'flex', alignItems: 'center', justifyContent: 'center',
          zIndex: 1000
        }} onClick={() => setShowStudentModal(false)}>
          <div style={{
            background: 'white', borderRadius: '12px', boxShadow: '0 10px 40px rgba(0,0,0,0.2)',
            maxWidth: 600, width: '90%', maxHeight: '85vh', overflow: 'auto',
            animation: 'slideUp 0.3s ease'
          }} onClick={e => e.stopPropagation()}>
            <div style={{
              display: 'flex', alignItems: 'center', justifyContent: 'space-between',
              padding: '20px 24px', borderBottom: '1px solid var(--gray-200)'
            }}>
              <div>
                <h2 style={{ margin: 0, fontSize: 20, fontWeight: 600, color: 'var(--text)' }}>
                  {selected.studentName}
                </h2>
                <p style={{ margin: '4px 0 0 0', fontSize: 13, color: 'var(--gray-400)' }}>{selected.studentEmail}</p>
              </div>
              <button onClick={() => setShowStudentModal(false)} style={{
                background: 'none', border: 'none', fontSize: 24, color: 'var(--gray-400)',
                cursor: 'pointer', padding: 0, width: 32, height: 32, display: 'flex', alignItems: 'center', justifyContent: 'center'
              }}>×</button>
            </div>

            <div style={{ padding: '24px' }}>
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '20px', marginBottom: 20 }}>
                <div>
                  <label style={{ fontSize: 12, fontWeight: 600, color: 'var(--gray-400)', textTransform: 'uppercase' }}>Roll Number</label>
                  <div style={{ fontSize: 14, fontWeight: 500, color: 'var(--text)', marginTop: 4 }}>{selected.rollNumber || '—'}</div>
                </div>
                <div>
                  <label style={{ fontSize: 12, fontWeight: 600, color: 'var(--gray-400)', textTransform: 'uppercase' }}>Department</label>
                  <div style={{ fontSize: 14, color: 'var(--text)', marginTop: 4 }}>{getDeptAbbr(selected.department)}</div>
                </div>
                <div>
                  <label style={{ fontSize: 12, fontWeight: 600, color: 'var(--gray-400)', textTransform: 'uppercase' }}>CGPA</label>
                  <div style={{ fontSize: 14, fontWeight: 500, color: parseFloat(selected.cgpa) >= 8 ? 'var(--success)' : 'var(--text)', marginTop: 4 }}>{selected.cgpa || '—'}</div>
                </div>
              </div>

              <div style={{ borderTop: '1px solid var(--gray-200)', paddingTop: 20, marginBottom: 20 }}>
                <h3 style={{ fontSize: 13, fontWeight: 600, color: 'var(--text)', textTransform: 'uppercase', margin: '0 0 16px 0' }}>Application Status</h3>
                <div style={{ display: 'flex', flexDirection: 'column', gap: 12, fontSize: 13 }}>
                  {[
                    ['Status', <span className={`badge ${(STATUS_CFG[selected.status] || {}).cls}`}>{(STATUS_CFG[selected.status] || {}).label}</span>],
                    ['Applied', new Date(selected.appliedAt).toLocaleDateString('en-IN', { day: 'numeric', month: 'long', year: 'numeric' })],
                    selected.aptitudeScore != null && ['Aptitude Score', `${selected.aptitudeScore} — ${selected.aptitudeCleared ? '✅ Cleared' : '❌ Failed'}`],
                    selected.interviewDate && ['Interview Date', selected.interviewDate],
                    selected.interviewTime && ['Interview Time', selected.interviewTime],
                    selected.interviewMode && ['Interview Mode', selected.interviewMode],
                    selected.interviewResult && ['Interview Result', selected.interviewResult],
                    selected.interviewNotes && ['Notes', selected.interviewNotes],
                    selected.finalSelected != null && ['Final Decision', selected.finalSelected ? '✅ Selected' : '❌ Not Selected'],
                  ].filter(Boolean).map(([k, v]) => (
                    <div key={k} style={{ display: 'flex', gap: 8, borderBottom: '1px solid var(--gray-100)', paddingBottom: 10 }}>
                      <span style={{ color: 'var(--gray-400)', minWidth: 110, flexShrink: 0 }}>{k}</span>
                      <span style={{ color: 'var(--text-mid)', fontWeight: 500 }}>{v}</span>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Round Scheduling Modal */}
      {showRoundScheduling && selected && (
        <div className="modal-overlay" onClick={() => setShowRoundScheduling(false)}>
          <div className="modal" style={{ maxWidth: 700, maxHeight: '80vh', overflow: 'auto' }} onClick={e => e.stopPropagation()}>
            <AdminRoundScheduling appId={selected.id} onBack={() => { setShowRoundScheduling(false); fetchData(); }} />
          </div>
        </div>
      )}
    </>
  );
}
